import React, { useEffect, useState } from 'react';
import { Pie, Bar, Line, Doughnut } from 'react-chartjs-2';
import axios from 'axios';
import './Reports.css';

import {
  Chart as ChartJS,
  ArcElement,
  BarElement,
  LineElement,
  PointElement,
  CategoryScale,
  LinearScale,
  Title,
  Tooltip,
  Legend,
} from 'chart.js';

ChartJS.register(
  ArcElement,
  BarElement,
  LineElement,
  PointElement,
  CategoryScale,
  LinearScale,
  Title,
  Tooltip,
  Legend
);

function Reports() {
  const [data, setData] = useState({
    chartData: null,
    predictions: null,
    categoryAnalysis: null,
    brandAnalysis: null,
    topProducts: null,
    priceDistribution: null,
    ratingDistribution: null,
    forecast: null
  });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchAllData = async () => {
      try {
        console.log('Starting to fetch analytics data...');

        const responses = await Promise.allSettled([
          axios.get('http://localhost:5000/api/ml/analytics'),
          axios.get('http://localhost:5000/api/ml/ml-demand-prediction'),
          axios.get('http://localhost:5000/api/ml/category-analysis'),
          axios.get('http://localhost:5000/api/ml/brand-analysis'),
          axios.get('http://localhost:5000/api/ml/top-products'),
          axios.get('http://localhost:5000/api/ml/price-distribution'),
          axios.get('http://localhost:5000/api/ml/rating-distribution'),
          axios.get('http://localhost:5000/api/ml/next-month-forecast')
        ]);

        const newData = {};
        const keys = ['chartData', 'predictions', 'categoryAnalysis', 'brandAnalysis', 'topProducts', 'priceDistribution', 'ratingDistribution', 'forecast'];

        responses.forEach((response, idx) => {
          if (response.status === 'fulfilled' && response.value.data) {
            newData[keys[idx]] = response.value.data;
            console.log(`✓ ${keys[idx]} loaded:`, response.value.data);
          } else {
            console.warn(`✗ ${keys[idx]} failed:`, response.reason?.message || 'Unknown error');
          }
        });

        setData(newData);
        setError(null);
      } catch (error) {
        console.error('Error fetching data:', error);
        setError(error.message);
      } finally {
        setLoading(false);
      }
    };
    fetchAllData();
  }, []);

  if (loading) {
    return <div className="reports-container"><p>⏳ Loading analytics... Make sure ML API is running on port 8000</p></div>;
  }

  if (error) {
    return <div className="reports-container"><p>❌ Error: {error}</p><p>Ensure Flask ML API is running: python api/app.py</p></div>;
  }

  const { chartData, predictions, categoryAnalysis, brandAnalysis, topProducts, priceDistribution, ratingDistribution, forecast } = data;

  const cardStyle = {
    background: 'linear-gradient(135deg, #1a3a52 0%, #2d5a80 100%)',
    color: 'white',
    padding: '24px',
    borderRadius: '12px',
    textAlign: 'center',
    boxShadow: '0 8px 16px rgba(26, 58, 82, 0.2)',
    transition: 'transform 0.3s, box-shadow 0.3s'
  };

  const valueStyle = {
    fontSize: '2rem',
    fontWeight: 'bold',
    margin: '0',
    color: '#ffd700'
  };

  return (
    <div className="reports-container">
      <h1>📊 Analytics & ML Predictions Dashboard</h1>

      {/* Next Month Forecast */}
      {forecast && (
        <div className="prediction-section">
          <h2>🤖 Next Month Forecast (Linear Regression)</h2>
          <div className="prediction-cards">
            <div style={cardStyle}>
              <h3>Current Month Sales</h3>
              <p style={valueStyle}>₹{Math.round(forecast.currentMonthSales * 83)}</p>
            </div>
            <div style={cardStyle}>
              <h3>Forecasted Next Month</h3>
              <p style={valueStyle}>₹{Math.round(forecast.nextMonthForecast * 83)}</p>
            </div>
            <div style={cardStyle}>
              <h3>Growth Rate</h3>
              <p style={{...valueStyle, color: '#4CAF50'}}>📈 {forecast.growthRate}</p>
            </div>
            <div style={cardStyle}>
              <h3>Model Confidence</h3>
              <p style={valueStyle}>{(parseFloat(forecast.confidence) * 100).toFixed(0)}%</p>
            </div>
          </div>
        </div>
      )}

      {/* Category Forecast */}
      {forecast?.categoryForecast && forecast.categoryForecast.length > 0 && (
        <div className="chart-section">
          <h2>📦 Category-wise Sales Forecast</h2>
          <table className="forecast-table">
            <thead>
              <tr>
                <th>Category</th>
                <th>Current Sales</th>
                <th>Forecasted Sales</th>
                <th>Growth</th>
              </tr>
            </thead>
            <tbody>
              {forecast.categoryForecast.map((cat, idx) => (
                <tr key={idx}>
                  <td>{cat.category}</td>
                  <td>{cat.currentSales}</td>
                  <td>{cat.forecastedSales}</td>
                  <td className="positive">{cat.growth}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* Charts */}
      {chartData?.pie?.labels && chartData.pie.labels.length > 0 && (
        <div className="chart-section">
          <h2>📊 Category Distribution</h2>
          <div style={{ position: 'relative', height: '400px' }}>
            <Pie data={chartData.pie} options={{ maintainAspectRatio: false }} />
          </div>
        </div>
      )}

      {chartData?.bar?.labels && chartData.bar.labels.length > 0 && (
        <div className="chart-section">
          <h2>💰 Average Price by Category</h2>
          <div style={{ position: 'relative', height: '400px' }}>
            <Bar data={chartData.bar} options={{ maintainAspectRatio: false }} />
          </div>
        </div>
      )}

      {chartData?.line?.labels && chartData.line.labels.length > 0 && (
        <div className="chart-section">
          <h2>📈 Monthly Sales Trend</h2>
          <div style={{ position: 'relative', height: '400px' }}>
            <Line data={chartData.line} options={{ maintainAspectRatio: false }} />
          </div>
        </div>
      )}

      {/* Price Distribution */}
      {priceDistribution?.ranges && priceDistribution.ranges.length > 0 && (
        <div className="chart-section">
          <h2>💵 Price Range Distribution</h2>
          <div style={{ position: 'relative', height: '400px' }}>
            <Bar data={{
              labels: priceDistribution.ranges,
              datasets: [{
                label: 'Number of Products',
                data: priceDistribution.counts,
                backgroundColor: 'rgba(153, 102, 255, 0.2)',
                borderColor: 'rgba(153, 102, 255, 1)',
                borderWidth: 1
              }]
            }} options={{ maintainAspectRatio: false }} />
          </div>
        </div>
      )}

      {/* Rating Distribution */}
      {ratingDistribution?.ratings && ratingDistribution.ratings.length > 0 && (
        <div className="chart-section">
          <h2>⭐ Rating Distribution</h2>
          <div style={{ position: 'relative', height: '400px' }}>
            <Doughnut data={{
              labels: ratingDistribution.ratings.map(r => `${r} Stars`),
              datasets: [{
                data: ratingDistribution.counts,
                backgroundColor: ['#FF6384', '#36A2EB', '#FFCE56', '#4BC0C0', '#9966FF']
              }]
            }} options={{ maintainAspectRatio: false }} />
          </div>
        </div>
      )}

      {/* Top Products */}
      {topProducts?.topProducts && topProducts.topProducts.length > 0 && (
        <div className="chart-section">
          <h2>🏆 Top 15 Best Selling Products</h2>
          <table className="products-table">
            <thead>
              <tr>
                <th>Product Name</th>
                <th>Category</th>
                <th>Price</th>
                <th>Sales</th>
                <th>Rating</th>
              </tr>
            </thead>
            <tbody>
              {topProducts.topProducts.map((product, idx) => (
                <tr key={idx}>
                  <td>{product.name}</td>
                  <td>{product.category}</td>
                  <td>₹{Math.round(product.price)}</td>
                  <td>{product.sales}</td>
                  <td>⭐ {product.rating.toFixed(1)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* Category Analysis */}
      {categoryAnalysis?.categories && categoryAnalysis.categories.length > 0 && (
        <div className="chart-section">
          <h2>📋 Category Analysis</h2>
          <table className="analysis-table">
            <thead>
              <tr>
                <th>Category</th>
                <th>Avg Price</th>
                <th>Min Price</th>
                <th>Max Price</th>
                <th>Total Sales</th>
                <th>Avg Rating</th>
              </tr>
            </thead>
            <tbody>
              {categoryAnalysis.categories.map((cat, idx) => (
                <tr key={idx}>
                  <td>{cat.category}</td>
                  <td>₹{Math.round(cat.avgPrice)}</td>
                  <td>₹{Math.round(cat.minPrice)}</td>
                  <td>₹{Math.round(cat.maxPrice)}</td>
                  <td>{cat.totalSales}</td>
                  <td>⭐ {cat.avgRating.toFixed(1)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* Brand Analysis */}
      {brandAnalysis?.brands && brandAnalysis.brands.length > 0 && (
        <div className="chart-section">
          <h2>🏢 Top Brands Performance</h2>
          <table className="analysis-table">
            <thead>
              <tr>
                <th>Brand</th>
                <th>Total Sales</th>
                <th>Avg Rating</th>
                <th>Avg Price</th>
              </tr>
            </thead>
            <tbody>
              {brandAnalysis.brands.map((brand, idx) => (
                <tr key={idx}>
                  <td>{brand.brand}</td>
                  <td>{brand.totalSales}</td>
                  <td>⭐ {brand.avgRating.toFixed(1)}</td>
                  <td>₹{Math.round(brand.avgPrice)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* ML Predictions */}
      {predictions && predictions.results && predictions.results.length > 0 && (
        <div className="chart-section">
          <h2>🎯 ML Demand Predictions (Top 10)</h2>
          <div className="metrics">
            <div className="metric">
              <span>Model Accuracy (R²):</span>
              <strong>{(predictions.accuracy * 100).toFixed(1)}%</strong>
            </div>
            <div className="metric">
              <span>RMSE:</span>
              <strong>{predictions.rmse}</strong>
            </div>
          </div>
          <table className="predictions-table">
            <thead>
              <tr>
                <th>Product</th>
                <th>Category</th>
                <th>Price</th>
                <th>Actual Sales</th>
                <th>Predicted Sales</th>
              </tr>
            </thead>
            <tbody>
              {predictions.results.slice(0, 10).map((item, idx) => (
                <tr key={idx}>
                  <td>{item.name}</td>
                  <td>{item.category}</td>
                  <td>₹{Math.round(item.price)}</td>
                  <td>{Math.round(item.actual)}</td>
                  <td className="positive">{Math.round(item.predicted)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

export default Reports;
